export type Category = {
  id: string;
  name: string;
  color: string;
};

export type Marker = {
  id: string;
  title: string;
  description: string;
  lat: number;
  lng: number;
  category: string;
  createdAt: string;
};

export type Circle = {
  id: string;
  lat: number;
  lng: number;
  radius: number;
  color: string;
  label: string;
  createdAt: string;
};

import type { Marker, Circle, Category } from './types';

const MARKERS_PATH = 'data/markers.json';
const CIRCLES_PATH = 'data/circles.json';
const CATEGORIES_PATH = 'data/categories.json';

const readJson = async <T>(path: string): Promise<T> => {
  const file = Bun.file(path);
  return file.json() as Promise<T>;
};

const writeJson = async <T>(path: string, data: T): Promise<void> => {
  await Bun.write(path, JSON.stringify(data, null, 2));
};

const generateId = (): string =>
  Date.now().toString(36) + Math.random().toString(36).slice(2, 8);

// Categories
export const getCategories = (): Promise<Category[]> =>
  readJson<Category[]>(CATEGORIES_PATH);

// Markers
export const getMarkers = async (category?: string): Promise<Marker[]> => {
  const markers = await readJson<Marker[]>(MARKERS_PATH);
  if (category) {
    return markers.filter((m) => m.category === category);
  }
  return markers;
};

export const addMarker = async (input: {
  title: string;
  description: string;
  lat: number;
  lng: number;
  category: string;
}): Promise<Marker> => {
  const markers = await readJson<Marker[]>(MARKERS_PATH);
  const marker: Marker = {
    id: generateId(),
    ...input,
    createdAt: new Date().toISOString(),
  };
  markers.push(marker);
  await writeJson(MARKERS_PATH, markers);
  return marker;
};

export const deleteMarker = async (id: string): Promise<boolean> => {
  const markers = await readJson<Marker[]>(MARKERS_PATH);
  const idx = markers.findIndex((m) => m.id === id);
  if (idx === -1) return false;
  markers.splice(idx, 1);
  await writeJson(MARKERS_PATH, markers);
  return true;
};

// Circles
export const getCircles = (): Promise<Circle[]> =>
  readJson<Circle[]>(CIRCLES_PATH);

export const addCircle = async (input: {
  lat: number;
  lng: number;
  radius: number;
  color: string;
  label: string;
}): Promise<Circle> => {
  const circles = await readJson<Circle[]>(CIRCLES_PATH);
  const circle: Circle = {
    id: generateId(),
    ...input,
    createdAt: new Date().toISOString(),
  };
  circles.push(circle);
  await writeJson(CIRCLES_PATH, circles);
  return circle;
};

export const deleteCircle = async (id: string): Promise<boolean> => {
  const circles = await readJson<Circle[]>(CIRCLES_PATH);
  const idx = circles.findIndex((c) => c.id === id);
  if (idx === -1) return false;
  circles.splice(idx, 1);
  await writeJson(CIRCLES_PATH, circles);
  return true;
};

export type SearchResult = {
  lat: number;
  lng: number;
  displayName: string;
};

export const geocode = async (query: string): Promise<SearchResult[]> => {
  const url = new URL('https://nominatim.openstreetmap.org/search');
  url.searchParams.set('q', query);
  url.searchParams.set('format', 'json');
  url.searchParams.set('limit', '5');

  const res = await fetch(url.toString(), {
    headers: { 'User-Agent': 'interactive-map-module/1.0' },
  });

  if (!res.ok) return [];

  const data = (await res.json()) as Array<{
    lat: string;
    lon: string;
    display_name: string;
  }>;

  return data.map((item) => ({
    lat: parseFloat(item.lat),
    lng: parseFloat(item.lon),
    displayName: item.display_name,
  }));
};

import { h, Fragment } from '@plaited/template'
import { createSSR } from '@plaited/template/ssr'

export const renderPage = (): string => {
  const template = h(Fragment, null,
    h('!DOCTYPE', { html: true }),
    h('html', { lang: 'en' },
      h('head', null,
        h('meta', { charset: 'UTF-8' }),
        h('meta', { name: 'viewport', content: 'width=device-width, initial-scale=1.0' }),
        h('title', null, 'Interactive Map'),
        h('link', {
          rel: 'stylesheet',
          href: 'https://unpkg.com/leaflet@1/dist/leaflet.css',
        }),
        h('script', { src: 'https://unpkg.com/leaflet@1/dist/leaflet.js' }),
        h('style', null, CSS_TEXT),
      ),
      h('body', null,
        h('div', { id: 'app' },
          h('aside', { id: 'sidebar' },
            h('h2', null, 'Interactive Map'),
            h('div', { id: 'search-box' },
              h('input', {
                type: 'text',
                id: 'search-input',
                placeholder: 'Search location...',
              }),
              h('button', { id: 'search-btn' }, 'Go'),
              h('ul', { id: 'search-results' }),
            ),
            h('div', { id: 'category-filter' },
              h('label', null, 'Filter by category:'),
              h('select', { id: 'category-select' },
                h('option', { value: '' }, 'All'),
              ),
            ),
            h('div', { id: 'marker-list' },
              h('h3', null, 'Markers'),
              h('ul', { id: 'markers-ul' }),
            ),
            h('div', { id: 'actions' },
              h('button', { id: 'add-marker-btn', class: 'primary-btn' }, '+ Add Marker'),
              h('button', { id: 'add-circle-btn', class: 'secondary-btn' }, '+ Add Circle'),
            ),
          ),
          h('div', { id: 'map' }),
        ),
        h('div', { id: 'modal-overlay', class: 'hidden' },
          h('div', { id: 'modal' },
            h('h3', { id: 'modal-title' }, 'Add Marker'),
            h('form', { id: 'modal-form' },
              h('div', { class: 'form-group' },
                h('label', null, 'Title'),
                h('input', { type: 'text', id: 'input-title', required: true }),
              ),
              h('div', { class: 'form-group', id: 'desc-group' },
                h('label', null, 'Description'),
                h('textarea', { id: 'input-desc', rows: '3' }),
              ),
              h('div', { class: 'form-group', id: 'category-group' },
                h('label', null, 'Category'),
                h('select', { id: 'input-category' }),
              ),
              h('div', { class: 'form-group', id: 'radius-group', style: 'display:none' },
                h('label', null, 'Radius (meters)'),
                h('input', { type: 'number', id: 'input-radius', value: '500', min: '10' }),
              ),
              h('div', { class: 'form-group', id: 'color-group', style: 'display:none' },
                h('label', null, 'Color'),
                h('input', { type: 'color', id: 'input-color', value: '#2196F3' }),
              ),
              h('p', { id: 'modal-coords' }),
              h('div', { class: 'form-actions' },
                h('button', { type: 'submit', class: 'primary-btn' }, 'Save'),
                h('button', { type: 'button', id: 'modal-cancel', class: 'secondary-btn' }, 'Cancel'),
              ),
            ),
          ),
        ),
        h('script', null, CLIENT_JS),
      ),
    ),
  )

  const ssr = createSSR()
  return ssr(template)
}

