const CLIENT_JS = `
(function() {
  let map, categories = [], markers = [], circles = [];
  let leafletMarkers = {}, leafletCircles = {};
  let pendingLatLng = null;
  let modalMode = 'marker';

  const init = async () => {
    map = L.map('map').setView([40, -30], 3);
    L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
      attribution: '&copy; OpenStreetMap contributors',
      maxZoom: 19,
    }).addTo(map);

    map.on('click', (e) => {
      pendingLatLng = e.latlng;
    });

    categories = await api('/api/categories');
    populateCategorySelects();
    await refreshMarkers();
    await refreshCircles();
  };

  const api = async (url, opts) => {
    const res = await fetch(url, opts);
    return res.json();
  };

  const populateCategorySelects = () => {
    const filterSel = document.getElementById('category-select');
    const inputSel = document.getElementById('input-category');
    categories.forEach(c => {
      filterSel.appendChild(new Option(c.name, c.id));
      inputSel.appendChild(new Option(c.name, c.id));
    });
  };

  const createIcon = (color) => {
    return L.divIcon({
      className: 'custom-marker',
      html: '<div style="width:28px;height:28px;border-radius:50% 50% 50% 0;background:' + color + ';transform:rotate(-45deg);border:3px solid #fff;box-shadow:0 2px 6px rgba(0,0,0,0.4);"></div>',
      iconSize: [28, 28],
      iconAnchor: [14, 28],
      popupAnchor: [0, -28],
    });
  };

  const refreshMarkers = async () => {
    const filter = document.getElementById('category-select').value;
    const url = filter ? '/api/markers?category=' + filter : '/api/markers';
    markers = await api(url);
    renderSidebar();
    renderMapMarkers();
  };

  const refreshCircles = async () => {
    circles = await api('/api/circles');
    renderMapCircles();
  };

  const renderSidebar = () => {
    const ul = document.getElementById('markers-ul');
    ul.innerHTML = '';
    const grouped = {};
    markers.forEach(m => {
      if (!grouped[m.category]) grouped[m.category] = [];
      grouped[m.category].push(m);
    });
    Object.keys(grouped).forEach(catId => {
      const cat = categories.find(c => c.id === catId) || { name: catId, color: '#999' };
      grouped[catId].forEach(m => {
        const li = document.createElement('li');
        li.className = 'marker-item';
        li.innerHTML =
          '<span class="marker-dot" style="background:' + cat.color + '"></span>' +
          '<div class="marker-info"><div class="m-title">' + esc(m.title) + '</div>' +
          '<div class="m-cat">' + esc(cat.name) + '</div></div>' +
          '<button class="marker-del" data-id="' + m.id + '">&times;</button>';
        li.addEventListener('click', (e) => {
          if (e.target.classList.contains('marker-del')) return;
          map.setView([m.lat, m.lng], 15);
          if (leafletMarkers[m.id]) leafletMarkers[m.id].openPopup();
        });
        li.querySelector('.marker-del').addEventListener('click', async () => {
          await api('/api/markers/' + m.id, { method: 'DELETE' });
          await refreshMarkers();
        });
        ul.appendChild(li);
      });
    });
    if (markers.length === 0) {
      ul.innerHTML = '<li style="padding:12px;color:#666;font-size:0.85rem;">No markers yet. Click the map then press "+ Add Marker".</li>';
    }
  };

  const renderMapMarkers = () => {
    Object.values(leafletMarkers).forEach(m => map.removeLayer(m));
    leafletMarkers = {};
    markers.forEach(m => {
      const cat = categories.find(c => c.id === m.category) || { color: '#2196F3' };
      const lm = L.marker([m.lat, m.lng], { icon: createIcon(cat.color) })
        .addTo(map)
        .bindPopup('<strong>' + esc(m.title) + '</strong><br>' + esc(m.description));
      leafletMarkers[m.id] = lm;
    });
  };

  const renderMapCircles = () => {
    Object.values(leafletCircles).forEach(c => map.removeLayer(c));
    leafletCircles = {};
    circles.forEach(c => {
      const lc = L.circle([c.lat, c.lng], {
        radius: c.radius, color: c.color, fillColor: c.color, fillOpacity: 0.15, weight: 2,
      }).addTo(map);
      if (c.label) lc.bindPopup('<strong>' + esc(c.label) + '</strong>');
      leafletCircles[c.id] = lc;
    });
  };

  const esc = (s) => {
    const d = document.createElement('div');
    d.textContent = s || '';
    return d.innerHTML;
  };

  // Search
  document.getElementById('search-btn').addEventListener('click', doSearch);
  document.getElementById('search-input').addEventListener('keydown', (e) => {
    if (e.key === 'Enter') doSearch();
  });

  async function doSearch() {
    const q = document.getElementById('search-input').value.trim();
    if (!q) return;
    const results = await api('/api/search?q=' + encodeURIComponent(q));
    const ul = document.getElementById('search-results');
    ul.innerHTML = '';
    results.forEach(r => {
      const li = document.createElement('li');
      li.textContent = r.displayName;
      li.addEventListener('click', () => {
        map.setView([r.lat, r.lng], 13);
        pendingLatLng = L.latLng(r.lat, r.lng);
        ul.innerHTML = '';
      });
      ul.appendChild(li);
    });
  }

  // Category filter
  document.getElementById('category-select').addEventListener('change', refreshMarkers);

  // Modal logic
  const overlay = document.getElementById('modal-overlay');
  const form = document.getElementById('modal-form');

  document.getElementById('add-marker-btn').addEventListener('click', () => {
    if (!pendingLatLng) { alert('Click on the map first to set a location.'); return; }
    modalMode = 'marker';
    document.getElementById('modal-title').textContent = 'Add Marker';
    document.getElementById('desc-group').style.display = '';
    document.getElementById('category-group').style.display = '';
    document.getElementById('radius-group').style.display = 'none';
    document.getElementById('color-group').style.display = 'none';
    document.getElementById('modal-coords').textContent = 'Lat: ' + pendingLatLng.lat.toFixed(5) + ', Lng: ' + pendingLatLng.lng.toFixed(5);
    overlay.classList.remove('hidden');
  });

  document.getElementById('add-circle-btn').addEventListener('click', () => {
    if (!pendingLatLng) { alert('Click on the map first to set a center.'); return; }
    modalMode = 'circle';
    document.getElementById('modal-title').textContent = 'Add Circle';
    document.getElementById('desc-group').style.display = 'none';
    document.getElementById('category-group').style.display = 'none';
    document.getElementById('radius-group').style.display = '';
    document.getElementById('color-group').style.display = '';
    document.getElementById('modal-coords').textContent = 'Center: ' + pendingLatLng.lat.toFixed(5) + ', ' + pendingLatLng.lng.toFixed(5);
    overlay.classList.remove('hidden');
  });

  document.getElementById('modal-cancel').addEventListener('click', () => {
    overlay.classList.add('hidden');
    form.reset();
  });

  form.addEventListener('submit', async (e) => {
    e.preventDefault();
    if (modalMode === 'marker') {
      await api('/api/markers', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          title: document.getElementById('input-title').value,
          description: document.getElementById('input-desc').value,
          lat: pendingLatLng.lat,
          lng: pendingLatLng.lng,
          category: document.getElementById('input-category').value || 'default',
        }),
      });
      await refreshMarkers();
    } else {
      await api('/api/circles', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          lat: pendingLatLng.lat,
          lng: pendingLatLng.lng,
          radius: parseInt(document.getElementById('input-radius').value) || 500,
          color: document.getElementById('input-color').value || '#2196F3',
          label: document.getElementById('input-title').value,
        }),
      });
      await refreshCircles();
    }
    overlay.classList.add('hidden');
    form.reset();
    pendingLatLng = null;
  });

  init();
})();
`

import { getMarkers, addMarker, deleteMarker, getCircles, addCircle, deleteCircle, getCategories } from './store';
import { geocode } from './search';
import { renderPage } from './render';

const PORT = parseInt(process.env.PORT || '3000', 10);

const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  });

const htmlResponse = (html: string): Response =>
  new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  });

const server = Bun.serve({
  port: PORT,
  fetch: async (req) => {
    const url = new URL(req.url);
    const { pathname } = url;
    const method = req.method;

    // Serve map page
    if (pathname === '/' && method === 'GET') {
      return htmlResponse(renderPage());
    }

    // Categories
    if (pathname === '/api/categories' && method === 'GET') {
      return jsonResponse(await getCategories());
    }

    // Markers
    if (pathname === '/api/markers' && method === 'GET') {
      const category = url.searchParams.get('category') || undefined;
      return jsonResponse(await getMarkers(category));
    }

    if (pathname === '/api/markers' && method === 'POST') {
      const body = await req.json() as {
        title: string;
        description: string;
        lat: number;
        lng: number;
        category: string;
      };
      if (!body.title || body.lat == null || body.lng == null) {
        return jsonResponse({ error: 'title, lat, lng required' }, 400);
      }
      const marker = await addMarker({
        title: body.title,
        description: body.description || '',
        lat: body.lat,
        lng: body.lng,
        category: body.category || 'default',
      });
      return jsonResponse(marker, 201);
    }

    if (pathname.startsWith('/api/markers/') && method === 'DELETE') {
      const id = pathname.split('/').pop()!;
      const ok = await deleteMarker(id);
      return ok ? jsonResponse({ ok: true }) : jsonResponse({ error: 'not found' }, 404);
    }

    // Circles
    if (pathname === '/api/circles' && method === 'GET') {
      return jsonResponse(await getCircles());
    }

    if (pathname === '/api/circles' && method === 'POST') {
      const body = await req.json() as {
        lat: number;
        lng: number;
        radius: number;
        color: string;
        label: string;
      };
      if (body.lat == null || body.lng == null) {
        return jsonResponse({ error: 'lat, lng required' }, 400);
      }
      const circle = await addCircle({
        lat: body.lat,
        lng: body.lng,
        radius: body.radius || 500,
        color: body.color || '#2196F3',
        label: body.label || '',
      });
      return jsonResponse(circle, 201);
    }

    if (pathname.startsWith('/api/circles/') && method === 'DELETE') {
      const id = pathname.split('/').pop()!;
      const ok = await deleteCircle(id);
      return ok ? jsonResponse({ ok: true }) : jsonResponse({ error: 'not found' }, 404);
    }

    // Search
    if (pathname === '/api/search' && method === 'GET') {
      const q = url.searchParams.get('q') || '';
      if (!q) return jsonResponse([]);
      const results = await geocode(q);
      return jsonResponse(results);
    }

    return jsonResponse({ error: 'not found' }, 404);
  },
});

console.log(`Interactive Map running on http://localhost:${server.port}`);
